def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = (1 - ratio) ** 4 + 0.3
        elif 0.7 < ratio <= 0.9:
            score = np.log1p((1 - ratio) * 10) + 0.15
        elif 0.4 < ratio <= 0.7:
            score = np.exp(-((ratio - 0.5) ** 2) * 20) + 0.05
        else:
            acc = 0.0
            for k in range(1, 10):
                val = ((-1) ** k) * (ratio ** (k + 2)) / (k * 2.0)
                acc += val
                if abs(val) < 1e-5:
                    break
            score = abs(acc) + 0.07
        neighbors_influence = 0.0
        max_influence = 0.0
        count_neighbors = 0
        for offset in range(1, 7):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff_ratio = abs(capacity - neighbor_capacity) / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 1.5)
                    influence = diff_ratio * weight * 0.1
                    neighbors_influence += influence
                    count_neighbors += 1
                    if influence > max_influence:
                        max_influence = influence
        if count_neighbors > 0:
            neighbors_influence = neighbors_influence / count_neighbors + max_influence * 0.3
        capacity_factor = max(np.sqrt(capacity), 1)
        priority = score + neighbors_influence / capacity_factor
        if priority < 0:
            priority = 0
        if priority > 1:
            priority = 1 + (priority - 1) / 2
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    min_finite = np.min(finite_priorities)
    range_finite = max_finite - min_finite if max_finite != min_finite else 1
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 4
        else:
            priorities[i] = (priorities[i] - min_finite) / range_finite
            if priorities[i] < 0:
                priorities[i] = 0
            elif priorities[i] > 1:
                priorities[i] = 1
        if priorities[i] == 0:
            priorities[i] = 0.01
    return priorities
